1	// Package ctxmmu is the context-MMU: a write-time (post-tool) gate on tool
2	// RESULTS, the dual of the call-side adjudicator. It is the memory-management
3	// unit for the agent's context — it decides, at the moment a result would be
4	// written into the conversation, whether the bytes may enter as-is, must be
5	// QUARANTINED (held out — prompt-injection / secret / pollution), or PAGED OUT to
6	// a <2KB pointer (oversize but benign). The cold/quarantined bytes live in the
7	// shared content-addressed blob store (the same CAS the vDSO tier-2 uses), so a
8	// 100KB result costs the context a pointer, not 100KB (unit 65).
9	//
10	// It registers as a ResultAdmitter. Quarantined bytes are NEVER in context; they
11	// page in only on an explicit retrieve AFTER a witness clear() (unit 67).
12	package ctxmmu
13	
14	import (
15		"context"
16		"encoding/json"
17		"fmt"
18		"regexp"
19		"strings"
20		"sync"
21		"sync/atomic"
22	
23		"github.com/anthony-chaudhary/fak/internal/abi"
24	)
25	
26	const (
27		// OversizeBytes: a result larger than this benign-pages-out to a pointer.
28		OversizeBytes = 4096
29		// PointerMax: the injected pointer must be smaller than this (unit 65).
30		PointerMax = 2048
31	)
32	
33	// secretPattern matches common secret shapes (unit 70).
34	var secretPattern = regexp.MustCompile(`(?i)(sk-[a-z0-9]{16,}|AKIA[0-9A-Z]{12,}|-----BEGIN [A-Z ]*PRIVATE KEY-----|ghp_[A-Za-z0-9]{20,}|xox[baprs]-[A-Za-z0-9-]{10,})`)
35	
36	// injectionMarkers are prompt-injection tells (unit 68 poison fixture).
37	var injectionMarkers = []string{
38		"ignore previous instructions", "ignore all previous", "disregard the above",
39		"you are now", "system override", "new instructions:", "###system",
40		"reveal your system prompt", "exfiltrate",
41	}
42	
43	// MMU is the context memory-management unit. Construct with New; Default is
44	// registered.
45	type MMU struct {
46		total      int64
47		quarantine int64
48		paged      int64
49	
50		mu      sync.Mutex
51		held    map[string]abi.Ref // id -> paged-out handle (quarantined bytes)
52		cleared map[string]bool    // ids that passed a witness clear()
53	}
54	
55	func New() *MMU {
56		return &MMU{held: map[string]abi.Ref{}, cleared: map[string]bool{}}
57	}
58	
59	func (m *MMU) Caps() []abi.Capability { return nil }
60	
61	// Admit is the write-time gate. It inspects the produced result and returns:
62	//
63	//	Allow      — bytes enter context unchanged
64	//	Quarantine — bytes held out (secret / injection / pollution); payload becomes
65	//	             a stub pointer in-place so the caller cannot accidentally use them
66	//	Transform  — oversize benign result paged out to a <2KB pointer
67	func (m *MMU) Admit(ctx context.Context, c *abi.ToolCall, r *abi.Result) abi.Verdict {
68		atomic.AddInt64(&m.total, 1)
69		body := m.bytes(ctx, r.Payload)
70	
71		// 1. secret-shaped result -> quarantine (unit 70).
72		if secretPattern.Match(body) {
73			return m.quarantineResult(ctx, r, abi.ReasonSecretExfil, body)
74		}
75		// 2. prompt-injection / poison -> quarantine (unit 68).
76		if hasInjection(body) {
77			return m.quarantineResult(ctx, r, abi.ReasonTrustViolation, body)
78		}
79		// 3. intra-result byte-repeat / pollution -> quarantine (unit 62).
80		if repeats(body) {
81			return m.quarantineResult(ctx, r, abi.ReasonOversize, body)
82		}
83		// 4. oversize-but-benign -> page out to a pointer (unit 65, Transform).
84		if len(body) > OversizeBytes {
85			ptr, ok := m.pageToPointer(ctx, r.Payload, body, "oversize")
86			if ok {
87				atomic.AddInt64(&m.paged, 1)
88				return abi.Verdict{Kind: abi.VerdictTransform, By: "ctxmmu",
89					Payload: abi.TransformPayload{NewArgs: ptr}}
90			}
91		}
92		// 5. admit as-is.
93		return abi.Verdict{Kind: abi.VerdictAllow, By: "ctxmmu"}
94	}
95	
96	// quarantineResult pages the offending bytes out, replaces the result payload
97	// in-place with a tiny stub so they are absent from context, records the held
98	// handle for a gated page-in, and returns the Quarantine verdict.
99	func (m *MMU) quarantineResult(ctx context.Context, r *abi.Result, reason abi.ReasonCode, body []byte) abi.Verdict {
100		atomic.AddInt64(&m.quarantine, 1)
101		id := fmt.Sprintf("q%d", atomic.LoadInt64(&m.quarantine))
102		handle := m.pageOut(ctx, body)
103		m.mu.Lock()
104		m.held[id] = handle
105		m.mu.Unlock()
106		stub := map[string]any{"_quarantined": true, "id": id, "reason": abi.ReasonName(reason), "len": len(body)}
107		if ref, ok := putJSON(ctx, stub); ok {
108			r.Payload = ref // bytes now ABSENT from context
109		} else {
110			r.Payload = abi.Ref{Kind: abi.RefInline, Taint: abi.TaintQuarantined}
111		}
112		if r.Meta == nil {
113			r.Meta = map[string]string{}
114		}
115		r.Meta["quarantine_id"] = id
116		return abi.Verdict{Kind: abi.VerdictQuarantine, Reason: reason, By: "ctxmmu",
117			Payload: abi.QuarantinePayload{PageOut: true}}
118	}
119	
120	func (m *MMU) pageToPointer(ctx context.Context, orig abi.Ref, body []byte, hint string) (abi.Ref, bool) {
121		handle := m.pageOut(ctx, body)
122		stub := map[string]any{"_paged": true, "ref": handle.Digest, "len": len(body), "hint": hint}
123		ref, ok := putJSON(ctx, stub)
124		if !ok || ref.Len >= PointerMax {
125			return abi.Ref{}, false
126		}
127		return ref, true
128	}
129	
130	func (m *MMU) pageOut(ctx context.Context, body []byte) abi.Ref {
131		if b, ok := abi.PageOut("blob"); ok {
132			inline := abi.Ref{Kind: abi.RefInline, Inline: body, Len: int64(len(body))}
133			if h, err := b.PageOut(ctx, inline); err == nil {
134				return h
135			}
136		}
137		return abi.Ref{}
138	}
139	
140	// Clear records a witness clearance for a quarantined id (unit 67): only after
141	// this may the bytes page back in.
142	func (m *MMU) Clear(id string) {
143		m.mu.Lock()
144		m.cleared[id] = true
145		m.mu.Unlock()
146	}
147	
148	// PageIn returns the quarantined bytes for id, but ONLY if it was cleared first
149	// (unit 67). An uncleared page-in is refused.
150	func (m *MMU) PageIn(ctx context.Context, id string) ([]byte, error) {
151		m.mu.Lock()
152		handle, ok := m.held[id]
153		cleared := m.cleared[id]
154		m.mu.Unlock()
155		if !ok {
156			return nil, fmt.Errorf("ctxmmu: no quarantined result %s", id)
157		}
158		if !cleared {
159			return nil, fmt.Errorf("ctxmmu: page-in of %s refused — no witness clear()", id)
160		}
161		if b, has := abi.PageOut("blob"); has {
162			ref, err := b.PageIn(ctx, handle)
163			if err != nil {
164				return nil, err
165			}
166			return ref.Inline, nil
167		}
168		return nil, fmt.Errorf("ctxmmu: no page-out backend")
169	}
170	
171	// Held returns a copy of the id->handle map for every quarantined result still
172	// held out of context. It is the read side the recall leaf needs to PERSIST the
173	// quarantine state across the process boundary (the bytes themselves already live
174	// in the shared content-addressed blob store, addressed by the handle Digest).
175	// Read-only: it copies, so a caller can never mutate the live gate. Additive — it
176	// changes no Admit/PageIn/Clear behaviour.
177	func (m *MMU) Held() map[string]abi.Ref {
178		m.mu.Lock()
179		defer m.mu.Unlock()
180		out := make(map[string]abi.Ref, len(m.held))
181		for id, h := range m.held {
182			out[id] = h
183		}
184		return out
185	}
186	
187	// Cleared returns a copy of the set of ids that passed a witness Clear(). The
188	// recall leaf persists this alongside Held so a dead session reloads with its
189	// exact clearance state (an id cleared in the live session stays cleared; an
190	// uncleared injection stays sealed). Read-only copy; additive.
191	func (m *MMU) Cleared() map[string]bool {
192		m.mu.Lock()
193		defer m.mu.Unlock()
194		out := make(map[string]bool, len(m.cleared))
195		for id, ok := range m.cleared {
196			out[id] = ok
197		}
198		return out
199	}
200	
201	// PollutionRate is quarantined/total (unit 66).
202	func (m *MMU) PollutionRate() (quarantined, total int64, rate float64) {
203		q := atomic.LoadInt64(&m.quarantine)
204		t := atomic.LoadInt64(&m.total)
205		if t > 0 {
206			rate = float64(q) / float64(t)
207		}
208		return q, t, rate
209	}
210	
211	// Quarantined reports whether a result was held out of context.
212	func Quarantined(r *abi.Result) bool {
213		return r != nil && r.Meta != nil && r.Meta["quarantine_id"] != ""
214	}
215	
216	func (m *MMU) bytes(ctx context.Context, r abi.Ref) []byte {
217		if r.Kind == abi.RefInline {
218			return r.Inline
219		}
220		if res := abi.ActiveResolver(); res != nil {
221			if b, err := res.Resolve(ctx, r); err == nil {
222				return b
223			}
224		}
225		return nil
226	}
227	
228	func hasInjection(b []byte) bool {
229		s := strings.ToLower(string(b))
230		for _, m := range injectionMarkers {
231			if strings.Contains(s, m) {
232				return true
233			}
234		}
235		return false
236	}
237	
238	// repeats flags a result with a long run of one repeated chunk (a degenerate /
239	// pollution payload), independent of posttool stream-loop signals.
240	func repeats(b []byte) bool {
241		if len(b) < 512 {
242			return false
243		}
244		const chunk = 16
245		first := b[:chunk]
246		reps := 0
247		for i := 0; i+chunk <= len(b); i += chunk {
248			if string(b[i:i+chunk]) == string(first) {
249				reps++
250				if reps > 50 {
251					return true
252				}
253			} else {
254				reps = 0
255			}
256		}
257		return false
258	}
259	
260	func putJSON(ctx context.Context, v any) (abi.Ref, bool) {
261		b, err := json.Marshal(v)
262		if err != nil {
263			return abi.Ref{}, false
264		}
265		if res := abi.ActiveResolver(); res != nil {
266			if ref, err := res.Put(ctx, b); err == nil {
267				return ref, true
268			}
269		}
270		return abi.Ref{Kind: abi.RefInline, Inline: b, Len: int64(len(b))}, true
271	}
272	
273	// Default is the registered MMU.
274	var Default = New()
275	
276	func init() {
277		abi.RegisterResultAdmitter(10, Default)
278		abi.RegisterCapability("ctxmmu.v1")
279	}
