203	// --- unit 65: oversize benign (non-repeating) => Transform to a <2KB pointer. -
204	
205	// distinctOversize builds a > n-byte body of valid-ish JSON-ish filler whose
206	// 16-byte aligned windows are all distinct (so the repeat detector never fires)
207	// and that contains no secret pattern or injection marker.
208	func distinctOversize(n int) []byte {
209		var b bytes.Buffer
210		b.WriteString(`{"x":"`)
211		i := 0
212		for b.Len() < n {
213			// Each token carries an incrementing counter so no 16-byte window repeats.
214			fmt.Fprintf(&b, "row-%08d-filler;", i)
215			i++
216		}
217		b.WriteString(`"}`)
218		return b.Bytes()
219	}
